package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetAllowMissingColumnNames_defaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNamesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames();
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNamesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_chainWithAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true).withAllowMissingColumnNames(true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_chainWithAllowMissingColumnNamesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreEmptyLines(true).withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }
}
